mapper.insert:

    SELECT SEQ_ROOM_NO.NEXTVAL FROM DUAL

INSERT INTO COOKING_CLASS (
    ROOM_NO, CLASS_NAME, CLASS_INFO, PASSCODE, USER_NO, IMAGE_NO
) VALUES (
    #{roomNo}, #{className}, #{classInfo}, #{passcode}, #{userNo}, #{imageNo}
)

mapper.update:
UPDATE COOKING_CLASS
CLASS_NAME = #{className}, CLASS_INFO = #{classInfo}, PASSCODE = #{passcode},
WHERE ROOM_NO = #{roomNo}

UPDATE COOKING_CLASS
SET DELETE_STATUS = 'Y'
WHERE ROOM_NO = #{roomNo}

UPDATE CLASS_ENROLL
SET MESSAGE_NO = (
    SELECT NVL(MAX(MESSAGE_NO), 0)
    FROM MESSAGE
    WHERE REF_NO = #{roomNo}
)
WHERE USER_NO = #{userNo}
  AND ROOM_NO = #{roomNo}

UPDATE COOKING_CLASS
SET IMAGE_NO = #{imageNo}
WHERE ROOM_NO = #{roomNo}

mapper.select:
SELECT IMAGE_NO
FROM COOKING_CLASS
WHERE ROOM_NO = #{roomNo}
